def sum_list(nums):
    total = 0
    for n in nums:
        total += n
    return total

def find_max(nums):
    if not nums:
        return None
    best = nums[0]
    for n in nums[1:]:
        if n > best:
            best = n
    return best

def count_vowels(s):
    vowels = set('aeiou')
    count = 0
    for ch in s.lower():
        if ch in vowels:
            count += 1
    return count

def factorial(n):
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

def binary_search(nums, target):
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target:
            return mid
        if nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def flatten_list(nested):
    result = []
    for sub in nested:
        result.extend(sub)
    return result
